#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  // Connect to the SQLite database
  sqlgen::SQLiteDB db("test_db.sqlite");

  // Start a transaction
  auto transaction = db.transaction();

  // Delete users who have not logged in since 2025-01-01
  auto result = sqlgen::delete_<User>(db)
    .where(sqlgen::less_<sqlgen::DateTime>(&User::last_login, sqlgen::DateTime(2025, 1, 1)));

  // Commit the transaction and return the result
  transaction.commit();
  return result;
}

} // namespace delete_inactive_users
```

