    .join<Product>().on(sqlgen::column<&OrderItem::product_id>() == sqlgen::column<&Product::product_id>())
    .where(sqlgen::column<&Customer::customer_id>() == customer_id)
    .order_by(sqlgen::column<&Order::order_date>(), sqlgen::order::desc);

