Here's the complete implementation of the function using the `sqlgen` library:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_product_sales_report {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string category;
};

struct Sale {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct CategoryReport {
  std::string category;
  int total_qty;
  double total_amt;
};

struct ProductSalesReport {
  static constexpr const char* tablename = "ProductSalesReport";
  static constexpr bool is_view = true;
  std::string category;
  int total_qty;
  double total_amt;
};

std::vector<CategoryReport> query_product_sales_report() {
    // Create database connection
    auto db = sqlgen::sqlite::connection::open("test_db.sqlite");

    // Build the query using sqlgen's fluent interface
    auto query = sqlgen::query<Product>()
        .inner_join<Sale>(sqlgen::on<Product, Sale>(&Product::product_id, &Sale::product_id))
        .group_by(&Product::category)
        .having(sqlgen::gt(sqlgen::sum(&Sale::amount), 5000))
        .select(
            &Product::category,
            sqlgen::sum(&Sale::quantity).as("total_qty"),
            sqlgen::sum(&Sale::amount).as("total_amt")
        );

    // Execute the query and get results as ProductSalesReport objects
    auto results = db.execute<ProductSalesReport>(query);

    // Convert ProductSalesReport to CategoryReport
    std::vector<CategoryReport> report;
    report.reserve(results.size());

    for (const auto& result : results) {
        report.push_back({
            result.category,
            result.total_qty,
            result.total_amt
        });
    }

    return report;
}

}  // namespace query_product_sales_report
```

Key points about this implementation:

1. **Database Connection**: Uses `sqlgen::sqlite::connection::open()` to connect to the SQLite database.

2. **Query Building**: Uses sqlgen's fluent interface to construct the SQL query:
   - `inner_join()` to join Product and Sale tables
   - `group_by()` to group by category
   - `having()` with `sqlgen::gt()` (greater than) to filter categories with total sales > 5000
   - `select()` with aggregate functions `sqlgen::sum()` to calculate totals

3. **Query Execution**: Uses `db.execute<ProductSalesReport>()` to execute the query and map results to the view struct.

4. **Result Conversion**: Converts from `ProductSalesReport` to `CategoryReport` since the function signature requires returning `CategoryReport` objects.

The sqlgen library automatically handles the SQL generation and result mapping based on the struct definitions and query builder methods.

