    auto result = sqlgen::create_table<UserProfile>(db)
      .column("user_id", &UserProfile::user_id)
      .column("username", &UserProfile::username)
      .column("email", &UserProfile::email)
      .column("age", &UserProfile::age, sqlgen::check("age >= 18"))
      .column("bio", &UserProfile::bio)
