#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  // Connect to the database
  sqlgen::SQLiteDB db("test_db.sqlite");

  try {
    // Begin transaction
    db.execute("BEGIN TRANSACTION");

    // Check if sender has sufficient funds and deduct amount
    auto deduct_result = db.update<Account>()
      .set(&Account::balance, &Account::balance - amount)
      .where(sqlgen::column(&Account::account_id) == from_account_id &&
             sqlgen::column(&Account::balance) >= amount)
      .execute();

    // If no rows were updated (insufficient funds or account not found), rollback
    if (deduct_result.rows_affected() == 0) {
      db.execute("ROLLBACK");
      return false;
    }

    // Add amount to receiver
    auto add_result = db.update<Account>()
      .set(&Account::balance, &Account::balance + amount)
      .where(sqlgen::column(&Account::account_id) == to_account_id)
      .execute();

    // If receiver account not found, rollback
    if (add_result.rows_affected() == 0) {
      db.execute("ROLLBACK");
      return false;
    }

    // Commit transaction if all operations succeeded
    db.execute("COMMIT");
    return true;

  } catch (const std::exception& e) {
    // Rollback on any exception
    try {
      db.execute("ROLLBACK");
    } catch (...) {
      // Ignore rollback errors during exception handling
    }
    return false;
  }
}

}  // namespace transaction_transfer_funds
```

