```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace right_join_departments_projects {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string name;
};

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  int department_id;
  std::string name;
};

struct DepProj {
  std::optional<std::string> department_name;
  std::string project_name;
};

/**
 * description: right_join_departments_projects.
 * This function demonstrates how to perform a right join between departments and projects using sqlgen read API.
 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 */
std::vector<DepProj> right_join_departments_projects() {
  // Create database connection
  sqlgen::sqlite::connection conn("test_db.sqlite");

  // Perform RIGHT JOIN between Department and Project tables
  // RIGHT JOIN ensures all departments are included, even those without projects
  auto results = sqlgen::read<DepProj>(conn,
    sqlgen::select(
      sqlgen::column<Department>(&Department::name).as(&DepProj::department_name),
      sqlgen::column<Project>(&Project::name).as(&DepProj::project_name)
    ).from(
      sqlgen::right_join<Department, Project>(
        sqlgen::on(&Department::department_id, &Project::department_id)
      )
    )
  );

  return results;
}

}  // namespace right_join_departments_projects
```

This implementation:

1. **Connects to the SQLite database** "test_db.sqlite" using `sqlgen::sqlite::connection`
2. **Performs a RIGHT JOIN** between the `Department` and `Project` tables using `sqlgen::right_join`
3. **Uses the ON clause** to join on the `department_id` field that exists in both tables
4. **Maps the columns** from the joined result to the `DepProj` struct using `sqlgen::column().as()`
5. **Returns the results** as a vector of `DepProj` objects

The RIGHT JOIN ensures that all departments are included in the result, even those that don't have any associated projects. For departments without projects, the `project_name` field will contain an empty string and the `department_name` will be populated from the Department table.

