#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>
#include <optional>

namespace analyze_temporal_data {

struct Event {
  sqlgen::PrimaryKey<int> event_id;
  std::string event_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  std::optional<sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">> end_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct TemporalAnalysis {
  int event_id;
  std::string event_name;
  int start_day;
  int start_month;
  int start_year;
  int start_hour;
  int start_minute;
  int start_second;
  int start_weekday;
  int64_t start_epoch;
  std::optional<double> duration_days;
};

/**
 * @brief Analyze temporal data for a collection of events.
 *
 * Inserts the provided events into a temporary SQLite table, runs a query
 * to extract date/time parts and compute duration, and returns the results
 * as a vector of TemporalAnalysis.
 *
 * @param events Vector of Event records to analyze.
 * @return std::vector<TemporalAnalysis> Analysis results for each event that has an end_time.
 */
std::vector<TemporalAnalysis> analyze_temporal_data(const std::vector<Event>& events) {
  // Connect to SQLite database
  sqlgen::sqlite::Connection conn("test_db.sqlite");

  // Create temporary table for events
  conn.execute(R"(
    CREATE TEMPORARY TABLE IF NOT EXISTS temp_events (
      event_id INTEGER PRIMARY KEY,
      event_name TEXT NOT NULL,
      start_time DATETIME NOT NULL,
      end_time DATETIME,
      created_at DATETIME NOT NULL
    )
  )");

  // Clear any existing data from temporary table
  conn.execute("DELETE FROM temp_events");

  // Insert events into temporary table
  for (const auto& event : events) {
    std::string sql = "INSERT INTO temp_events (event_id, event_name, start_time, end_time, created_at) VALUES (";
    sql += std::to_string(event.event_id.value) + ", ";
    sql += "'" + event.event_name + "', ";
    sql += "'" + event.start_time.value + "', ";

    if (event.end_time.has_value()) {
      sql += "'" + event.end_time.value().value + "', ";
    } else {
      sql += "NULL, ";
    }

    sql += "'" + event.created_at.value + "')";

    conn.execute(sql);
  }

  // Execute temporal analysis query
  std::string query = R"(
    SELECT 
      event_id,
      event_name,
      CAST(strftime('%d', start_time) AS INTEGER) as start_day,
      CAST(strftime('%m', start_time) AS INTEGER) as start_month,
      CAST(strftime('%Y', start_time) AS INTEGER) as start_year,
      CAST(strftime('%H', start_time) AS INTEGER) as start_hour,
      CAST(strftime('%M', start_time) AS INTEGER) as start_minute,
      CAST(strftime('%S', start_time) AS INTEGER) as start_second,
      CAST(strftime('%w', start_time) AS INTEGER) as start_weekday,
      CAST(strftime('%s', start_time) AS INTEGER) as start_epoch,
      CASE 
        WHEN end_time IS NOT NULL THEN 
          julianday(end_time) - julianday(start_time)
        ELSE NULL
      END as duration_days
    FROM temp_events
    WHERE end_time IS NOT NULL
  )";

  auto results = conn.executeQuery<TemporalAnalysis>(query);

  return results;
}

}  // namespace analyze_temporal_data
```

This implementation:

1. **Connects to the SQLite database** "test_db.sqlite" using sqlgen's SQLite connection
2. **Creates a temporary table** to store the events for analysis
3. **Inserts all provided events** into the temporary table
4. **Executes a comprehensive temporal analysis query** that:
   - Extracts date components (day, month, year, hour, minute, second) using SQLite's `strftime` function
   - Calculates weekday information (0=Sunday, 6=Saturday)
   - Converts timestamps to Unix epoch format
   - Computes duration in days using `julianday` function for precise date differences
5. **Filters events** to only include those with end times (as specified in the reference SQL)
6. **Returns the analysis results** as a vector of `TemporalAnalysis` structs

The implementation uses SQLite's built-in date/time functions since SQLite doesn't have the exact functions mentioned in the reference SQL (DAY, MONTH, YEAR, etc.), but provides equivalent functionality through `strftime` and `julianday` functions.

