 * description: upsert_inventory_items.
 * This function demonstrates how to use upsert (insert or replace) statements in sqlgen write API.
 * It inserts or replaces the given inventory items in the Inventory table.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  try {
    // Create database connection
    sqlgen::SQLiteDatabase db("test_db.sqlite");

    // Create table if it doesn't exist
    db.createTable<Inventory>();

    // Perform upsert (insert or replace) operations
    for (const auto& item : items) {
      db.replace(item); // replace = INSERT OR REPLACE in SQLite
    }

    // Verify upsert behavior by reading back items
    for (const auto& item : items) {
      auto result = db.select<Inventory>().where(db.column(&Inventory::item_id) == item.item_id).execute();

      if (result.empty()) {
        std::cerr << "Verification failed: Item with ID " << item.item_id << " not found after upsert" << std::endl;
        return false;
      }

      const auto& retrieved_item = result[0];
      if (retrieved_item.name != item.name || retrieved_item.quantity != item.quantity) {
        std::cerr << "Verification failed: Data mismatch for item ID " << item.item_id << std::endl;
        std::cerr << "Expected: name=" << item.name << ", quantity=" << item.quantity << std::endl;
        std::cerr << "Actual: name=" << retrieved_item.name << ", quantity=" << retrieved_item.quantity << std::endl;
        return false;
      }
    }

    std::cout << "Upsert operation completed successfully. All " << items.size() << " items verified." << std::endl;
    return true;

  } catch (const std::exception& e) {
    std::cerr << "Error in upsert_inventory_items: " << e.what() << std::endl;
    return false;
  }
}

}  // namespace upsert_inventory_items
