        HAVING friend_count > (
          SELECT AVG(friend_count) 
          FROM (SELECT COUNT(*) as friend_count FROM Friendship GROUP BY user_id1) as subq
        )
        ORDER BY friend_count DESC
    )");

    // 3. Find friend-of-friend relationships (people connected through exactly one mutual friend)
    auto friend_of_friend = conn.query<FriendConnection>(R"(
        SELECT DISTINCT u1.username as user1_name, u3.username as user2_name, 1 as mutual_friends_count
        FROM User u1
        JOIN Friendship f1 ON u1.user_id = f1.user_id1
        JOIN User u2 ON f1.user_id2 = u2.user_id
        JOIN Friendship f2 ON u2.user_id = f2.user_id1
        JOIN User u3 ON f2.user_id2 = u3.user_id
        WHERE u1.user_id != u3.user_id
          AND NOT EXISTS (
            SELECT 1 FROM Friendship f3 
            WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u3.user_id
          )
    )");

    // 4. Count friends per user and identify most connected users
    auto friend_counts = conn.query<UserFriendCount>(R"(
        SELECT u.user_id, u.username, COUNT(f.user_id2) as friend_count
        FROM User u
        LEFT JOIN Friendship f ON u.user_id = f.user_id1
        GROUP BY u.user_id, u.username
        ORDER BY friend_count DESC
    )");

    // 5. Find users in the same city who are not yet friends (recommendation)
    auto recommendations = conn.query<FriendRecommendation>(R"(
        SELECT u1.username as user1_name, u2.username as user2_name, u1.city as city
        FROM User u1
        JOIN User u2 ON u1.city = u2.city AND u1.user_id < u2.user_id
        WHERE u1.city IS NOT NULL 
          AND NOT EXISTS (
            SELECT 1 FROM Friendship f 
            WHERE (f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id)
               OR (f.user_id1 = u2.user_id AND f.user_id2 = u1.user_id)
          )
    )");

    // Combine results - for simplicity, return mutual friends analysis
    results.insert(results.end(), mutual_friends.begin(), mutual_friends.end());

    return results;
}

}  // namespace analyze_social_network

