  int quantity_group;
  double estimated_profit;
};

/**
 * Calculate per-item order metrics by loading the provided items into a temporary SQLite table
 * and evaluating SQL expressions for totals, discounts, taxes, cost, grouping, and estimated profit.
 * @param items Vector of OrderItem records to analyze.
 * @return std::vector<OrderMetrics> Analysis results for each order item.
 */
std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  // Create SQLite database connection
  sqlgen::SQLiteDB db("test_db.sqlite");

  // Create temporary table for OrderItem data
  db.execute(R"(
    CREATE TEMPORARY TABLE IF NOT EXISTS OrderItem (
      item_id INTEGER PRIMARY KEY,
      order_id INTEGER NOT NULL,
      product_id INTEGER NOT NULL,
      unit_price REAL NOT NULL,
      quantity INTEGER NOT NULL,
      discount_rate REAL,
      tax_rate REAL
    )
  )");

  // Clear any existing data from temporary table
  db.execute("DELETE FROM OrderItem");

  // Insert all order items into the temporary table
  for (const auto& item : items) {
    db.execute(
      "INSERT INTO OrderItem (item_id, order_id, product_id, unit_price, quantity, discount_rate, tax_rate) "
      "VALUES (?, ?, ?, ?, ?, ?, ?)",
      item.item_id.value(),
      item.order_id,
      item.product_id,
      item.unit_price,
      item.quantity,
      item.discount_rate.value_or(0.0),
      item.tax_rate.value_or(0.0)
    );
  }

  // Execute the comprehensive metrics calculation query
  auto results = db.query<OrderMetrics>(R"(
    SELECT 
      item_id,
      order_id,
      product_id,
      unit_price,
      quantity,
      COALESCE(discount_rate, 0) as discount_rate,
      COALESCE(tax_rate, 0) as tax_rate,
      (unit_price * quantity) as gross_total,
      (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100)) as discounted_total,
      (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100) * (1 + COALESCE(tax_rate, 0)/100)) as final_total,
      (unit_price * quantity / quantity) as unit_cost,
      (quantity % 10) as quantity_group,
      (unit_price * 0.3) as estimated_profit
    FROM OrderItem
    ORDER BY item_id
  )");

  return results;
}

}  // namespace calculate_order_metrics
```

This implementation:

1. **Creates a temporary SQLite table** to store the input `OrderItem` data
2. **Inserts all provided items** into the temporary table using parameterized queries
3. **Executes the comprehensive SQL query** that performs all required arithmetic operations:
   - **Multiplication**: `unit_price * quantity` for gross total
   - **Division and percentage calculations**: Applying discount and tax rates
   - **Modulo operation**: `quantity % 10` for quantity grouping
   - **Additional calculations**: Unit cost and estimated profit
4. **Uses COALESCE** to handle NULL values in discount_rate and tax_rate fields
5. **Returns the complete analysis** as a vector of `OrderMetrics` structures

The function properly handles the optional discount and tax rates by providing default values (0.0) when they are not present, ensuring all calculations work correctly even with missing data.

