 */
bool inventory_bulk_write_and_read(const std::vector<Inventory>& items) {
    // Connect to SQLite database
    sqlgen::SQLiteDB db("test_db.sqlite");

    // Bulk insert using transaction for better performance
    db.execute("BEGIN TRANSACTION");

    for (const auto& item : items) {
        db.execute(
            "INSERT INTO Inventory(item_id, name, quantity, location) VALUES (?, ?, ?, ?)",
            item.item_id, item.name, item.quantity, item.location
