                  << " child records were automatically deleted" << std::endl;
    } else {
        std::cerr << "Cascade delete failed: " << children_after.size() 
                  << " child records still exist after parent deletion" << std::endl;
    }

    // Clean up: drop tables
    db.dropTable<Child>();
    db.dropTable<Parent>();

    return cascade_worked;

  } catch (const std::exception& e) {
    std::cerr << "Error in cascade_delete_demo: " << e.what() << std::endl;
    return false;
  }
