  try {
    // Connect to SQLite database
    sqlgen::sqlite::connection conn("test_db.sqlite");

    // Create Account table
    conn.execute(R"(
      DROP TABLE IF EXISTS Account;
      CREATE TABLE Account (
        account_id INTEGER PRIMARY KEY,
        balance REAL NOT NULL,
        status TEXT NOT NULL
      );
    )");

    // Insert initial test data
    conn.execute(R"(
      INSERT INTO Account (account_id, balance, status) VALUES
      (1, 1000.0, 'active'),
      (2, 2500.0, 'active'),
      (3, 500.0, 'inactive'),
      (4, 7500.0, 'active');
    )");

    // Update balances and statuses using set operations
    // Example 1: Update single account
    conn.update<Account>()
        .set(&Account::balance, 1500.0)
        .set(&Account::status, "premium")
        .where(sqlgen::column(&Account::account_id) == 1)
        .execute();

    // Example 2: Update multiple accounts with conditions
    conn.update<Account>()
        .set(&Account::balance, sqlgen::column(&Account::balance) * 1.1)  // 10% increase
        .set(&Account::status, "updated")
        .where(sqlgen::column(&Account::balance) > 1000.0)
        .execute();

    // Example 3: Update based on current status
    conn.update<Account>()
        .set(&Account::balance, 0.0)
        .set(&Account::status, "closed")
        .where(sqlgen::column(&Account::status) == "inactive")
        .execute();

    // Verify changes persisted by querying the data
    auto results = conn.select<Account>()
                      .columns(&Account::account_id, &Account::balance, &Account::status)
                      .order_by(&Account::account_id)
                      .execute();

    // Expected results after updates:
    // Account 1: balance=1500.0, status="premium" (specific update)
    // Account 2: balance=2750.0 (2500*1.1), status="updated" (10% increase)
    // Account 3: balance=0.0, status="closed" (inactive account closed)
    // Account 4: balance=8250.0 (7500*1.1), status="updated" (10% increase)

    bool verification_passed = true;

    if (results.size() != 4) {
        std::cerr << "Error: Expected 4 accounts, found " << results.size() << std::endl;
        return false;
    }

    // Verify account 1
    if (results[0].account_id != 1 || results[0].balance != 1500.0 || results[0].status != "premium") {
        std::cerr << "Account 1 verification failed" << std::endl;
        verification_passed = false;
    }

    // Verify account 2
    if (results[1].account_id != 2 || results[1].balance != 2750.0 || results[1].status != "updated") {
        std::cerr << "Account 2 verification failed" << std::endl;
        verification_passed = false;
    }

    // Verify account 3
    if (results[2].account_id != 3 || results[2].balance != 0.0 || results[2].status != "closed") {
        std::cerr << "Account 3 verification failed" << std::endl;
        verification_passed = false;
    }

    // Verify account 4
    if (results[3].account_id != 4 || results[3].balance != 8250.0 || results[3].status != "updated") {
        std::cerr << "Account 4 verification failed" << std::endl;
        verification_passed = false;
    }

    if (verification_passed) {
        std::cout << "All updates verified successfully!" << std::endl;
    }

    return verification_passed;

  } catch (const std::exception& e) {
    std::cerr << "Error in update_set_operations: " << e.what() << std::endl;
    return false;
  }
}

}  // namespace update_set_operations
