#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  // Create database connection
  sqlgen::SQLiteDB db("test_db.sqlite");

  // Since SQLite doesn't natively support FULL JOIN, we simulate it using UNION of LEFT JOIN and RIGHT JOIN
  // First part: LEFT JOIN (all suppliers with their products)
  auto left_join_query = sqlgen::query<SupProd>()
    .select(
      sqlgen::column<&Supplier::name>("supplier_name"),
      sqlgen::column<&Product::name>("product_name")
    )
    .from<Supplier>()
    .left_join<Product>(sqlgen::on<&Supplier::supplier_id, &Product::supplier_id>());

  // Second part: RIGHT JOIN simulated using LEFT JOIN with reversed tables
  // (all products that don't have matching suppliers)
  auto right_join_query = sqlgen::query<SupProd>()
    .select(
      sqlgen::column<&Supplier::name>("supplier_name"),
      sqlgen::column<&Product::name>("product_name")
    )
    .from<Product>()
    .left_join<Supplier>(sqlgen::on<&Product::supplier_id, &Supplier::supplier_id>())
    .where(sqlgen::is_null<&Supplier::supplier_id>());

  // Combine both queries using UNION to simulate FULL JOIN
  auto full_join_query = left_join_query.union_(right_join_query);

  // Execute the query and return results
  return db.execute(full_join_query);
}

}  // namespace full_join_suppliers_products

