```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  JoinAnalysis analysis;

  // Create SQLite database connection
  sqlgen::sqlite::connection conn("test_db.sqlite");

  // Create tables if they don't exist
  conn.execute(R"(
    CREATE TABLE IF NOT EXISTS Department (
      department_id INTEGER PRIMARY KEY,
      department_name TEXT NOT NULL,
      location TEXT
    )
  )");

  conn.execute(R"(
    CREATE TABLE IF NOT EXISTS Employee (
      employee_id INTEGER PRIMARY KEY,
      department_id INTEGER,
      first_name TEXT NOT NULL,
      last_name TEXT NOT NULL,
      salary REAL NOT NULL,
      FOREIGN KEY (department_id) REFERENCES Department(department_id)
    )
  )");

  // Clear existing data
  conn.execute("DELETE FROM Employee");
  conn.execute("DELETE FROM Department");

  // Insert department data
  for (const auto& dept : depts) {
    conn.execute(
      sqlgen::insert_into<Department>()
        .values(dept.department_id, dept.department_name, dept.location)
    );
  }

  // Insert employee data
  for (const auto& emp : emps) {
    conn.execute(
      sqlgen::insert_into<Employee>()
        .values(emp.employee_id, emp.department_id, emp.first_name, emp.last_name, emp.salary)
    );
  }

  // 1. INNER JOIN: Employees with assigned departments
  auto inner_join_query = sqlgen::select(
    sqlgen::columns(&Department::department_name, &Employee::first_name, &Employee::last_name, &Employee::salary),
    sqlgen::from<Department>().inner_join<Employee>().on(&Department::department_id, &Employee::department_id)
  );

  auto inner_results = conn.execute(inner_join_query);
  for (const auto& row : inner_results) {
    JoinResult result;
    result.department_name = std::get<0>(row);
    result.first_name = std::get<1>(row);
    result.last_name = std::get<2>(row);
    result.salary = std::get<3>(row);
    analysis.inner_join_results.push_back(result);
  }

  // 2. LEFT JOIN: All employees (even without departments)
  auto left_join_query = sqlgen::select(
    sqlgen::columns(&Department::department_name, &Employee::first_name, &Employee::last_name, &Employee::salary),
    sqlgen::from<Employee>().left_join<Department>().on(&Employee::department_id, &Department::department_id)
  );

  auto left_results = conn.execute(left_join_query);
  for (const auto& row : left_results) {
    JoinResult result;
    result.department_name = std::get<0>(row);
    result.first_name = std::get<1>(row);
    result.last_name = std::get<2>(row);
    result.salary = std::get<3>(row);
    analysis.left_join_results.push_back(result);
  }

  // 3. RIGHT JOIN: All departments (even without employees)
  // SQLite doesn't support RIGHT JOIN directly, so we emulate it by swapping tables in LEFT JOIN
  auto right_join_query = sqlgen::select(
    sqlgen::columns(&Department::department_name, &Employee::first_name, &Employee::last_name, &Employee::salary),
    sqlgen::from<Department>().left_join<Employee>().on(&Department::department_id, &Employee::department_id)
  );

  auto right_results = conn.execute(right_join_query);
  for (const auto& row : right_results) {
    JoinResult result;
    result.department_name = std::get<0>(row);
    result.first_name = std::get<1>(row);
    result.last_name = std::get<2>(row);
    result.salary = std::get<3>(row);
    analysis.right_join_results.push_back(result);
  }

  // 4. FULL JOIN: All employees and departments
  // SQLite doesn't support FULL JOIN directly, so we use UNION of LEFT and RIGHT joins
  auto full_join_query = conn.prepare(R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Department d
    LEFT JOIN Employee e ON d.department_id = e.department_id
    UNION ALL
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Employee e
    LEFT JOIN Department d ON e.department_id = d.department_id
    WHERE d.department_id IS NULL
  )");

  auto full_results = conn.execute(full_join_query);
  for (const auto& row : full_results) {
    JoinResult result;
    result.department_name = row.get<std::string>(0);
    result.first_name = row.get<std::string>(1);
    result.last_name = row.get<std::string>(2);
    result.salary = row.get<double>(3);
    analysis.full_join_results.push_back(result);
  }

  return analysis;
}

}  // namespace analyze_department_employees
```

This implementation:

1. **Connects to SQLite database** - Creates/opens "test_db.sqlite"
2. **Creates tables** - Uses CREATE TABLE IF NOT EXISTS for Department and Employee tables
3. **Inserts data** - Clears existing data and inserts the provided department and employee data
4. **Performs all four join types**:
   - **INNER JOIN** - Employees with assigned departments
   - **LEFT JOIN** - All employees (including those without departments)
   - **RIGHT JOIN** - All departments (including those without employees), emulated since SQLite doesn't support RIGHT JOIN directly
   - **FULL JOIN** - All employees and departments, using UNION to emulate FULL JOIN
5. **Returns comprehensive analysis** - Populates the JoinAnalysis structure with results from all join operations

The function handles SQLite's limitations by emulating RIGHT JOIN and FULL JOIN operations, and uses the sqlgen library's type-safe query building capabilities while falling back to raw SQL where necessary for complex operations.

